// EXHAUSTIVE PEST AND DISEASE DATABASE – ENRICHED VERSION
// Each pest has feedingType ("chewing" / "sucking")
// Each disease has pathogenType ("bacterial" / "fungal")
// Each chemical control has mode ("systemic" / "contact" / "both") and action ("preventive" / "curative" / "both")
// Biological controls added where available

export interface PestDisease {
  name: string;
  type: "pest" | "disease";
  feedingType?: "chewing" | "sucking";
  pathogenType?: "bacterial" | "fungal";
  chemicalControls: {
    productName: string;
    activeIngredient: string;
    rate: string;
    ratePerAcre: string;
    applicationMethod: string;
    timing: string;
    safetyInterval?: string;
    packageSizes?: string[];
    costPerPackage?: number;
    status?: "active" | "restricted" | "banned" | "check-locally";
    notes?: string;
    mode: "systemic" | "contact" | "both";
    action: "preventive" | "curative" | "both";
  }[];
  organicControls?: { method: string; preparation: string; application: string }[];
  biologicalControls?: { method: string; description: string }[];
  culturalControls: string[];
  businessNote?: string;
}

